use serde::Serialize;
use std::path::PathBuf;

#[derive(Debug, Clone, Serialize)]
pub struct Facet {
    pub id: usize,
    pub parent: Option<usize>,
    pub children: Vec<usize>,
    pub open: bool,
    pub cwd: PathBuf,
    pub label: String,
    pub last_command: Option<String>,
    #[serde(skip)]
    prev_open: usize,
    #[serde(skip)]
    next_open: usize,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FacetMove {
    Next,
    Prev,
}

#[derive(Debug, Serialize)]
pub struct FacetDeck {
    pub active: usize,
    pub open_count: usize,
    pub facets: Vec<Facet>,
}

impl FacetDeck {
    pub fn new(cwd: PathBuf) -> Self {
        let root = Facet {
            id: 0,
            parent: None,
            children: Vec::new(),
            open: true,
            cwd,
            label: "main".to_string(),
            last_command: None,
            prev_open: 0,
            next_open: 0,
        };
        Self {
            active: 0,
            open_count: 1,
            facets: vec![root],
        }
    }

    pub fn active(&self) -> &Facet {
        &self.facets[self.active]
    }

    pub fn active_mut(&mut self) -> &mut Facet {
        &mut self.facets[self.active]
    }

    pub fn fork_active(&mut self, command: Option<&str>) -> usize {
        let parent = self.active;
        let cwd = self.facets[parent].cwd.clone();
        let left = self.new_child(parent, cwd.clone(), "fork-left", command);
        let right = self.new_child_after(parent, left, cwd, "fork-right", None);
        self.facets[parent].children.push(left);
        self.facets[parent].children.push(right);
        self.active = left;
        left
    }

    pub fn next(&mut self) -> usize {
        self.active = self.facets[self.active].next_open;
        self.active
    }

    pub fn prev(&mut self) -> usize {
        self.active = self.facets[self.active].prev_open;
        self.active
    }

    pub fn close_active(&mut self) -> usize {
        if self.open_count <= 1 {
            return self.active;
        }
        let closing = self.active;
        let next = self.facets[closing].next_open;
        self.close_subtree(closing);
        self.active = if self.facets[next].open {
            next
        } else {
            self.first_open().unwrap_or(0)
        };
        self.active
    }

    pub fn close_children(&mut self) {
        let children = self.facets[self.active].children.clone();
        for child in children {
            self.close_subtree(child);
        }
    }

    pub fn close_all_others(&mut self) {
        let active = self.active;
        let mut cursor = Some(active);
        let mut keep = Vec::new();
        while let Some(id) = cursor {
            keep.push(id);
            cursor = self.facets[id].parent;
        }
        for id in 0..self.facets.len() {
            if !keep.contains(&id) {
                self.close_subtree(id);
            }
        }
        self.active = active;
    }

    pub fn note_command(&mut self, command: &str) {
        let active = self.active_mut();
        active.last_command = Some(command.to_string());
        if !command.trim().is_empty() {
            active.label = command.trim().chars().take(48).collect();
        }
    }

    pub fn sync_active_cwd_from_process(&mut self) {
        if let Ok(cwd) = std::env::current_dir() {
            self.active_mut().cwd = cwd;
        }
    }

    pub fn switch_result(&mut self, movement: FacetMove) -> usize {
        match movement {
            FacetMove::Next => self.next(),
            FacetMove::Prev => self.prev(),
        }
    }

    fn new_child(
        &mut self,
        parent: usize,
        cwd: PathBuf,
        label: &str,
        command: Option<&str>,
    ) -> usize {
        self.new_child_after(parent, parent, cwd, label, command)
    }

    fn new_child_after(
        &mut self,
        parent: usize,
        anchor: usize,
        cwd: PathBuf,
        label: &str,
        command: Option<&str>,
    ) -> usize {
        let id = self.facets.len();
        self.facets.push(Facet {
            id,
            parent: Some(parent),
            children: Vec::new(),
            open: true,
            cwd,
            label: command.unwrap_or(label).chars().take(48).collect(),
            last_command: command.map(str::to_string),
            prev_open: id,
            next_open: id,
        });
        self.link_after(anchor, id);
        self.open_count += 1;
        id
    }

    fn link_after(&mut self, anchor: usize, id: usize) {
        let next = self.facets[anchor].next_open;
        self.facets[id].prev_open = anchor;
        self.facets[id].next_open = next;
        self.facets[anchor].next_open = id;
        self.facets[next].prev_open = id;
    }

    fn unlink_open(&mut self, id: usize) {
        if !self.facets[id].open {
            return;
        }
        let prev = self.facets[id].prev_open;
        let next = self.facets[id].next_open;
        self.facets[prev].next_open = next;
        self.facets[next].prev_open = prev;
        self.facets[id].prev_open = id;
        self.facets[id].next_open = id;
        self.facets[id].open = false;
        self.open_count = self.open_count.saturating_sub(1);
    }

    fn close_subtree(&mut self, root: usize) {
        let mut stack = vec![root];
        while let Some(id) = stack.pop() {
            stack.extend(self.facets[id].children.iter().copied());
            self.unlink_open(id);
        }
    }

    fn first_open(&self) -> Option<usize> {
        self.facets
            .iter()
            .find(|facet| facet.open)
            .map(|facet| facet.id)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn deck() -> FacetDeck {
        FacetDeck::new(PathBuf::from("/tmp"))
    }

    #[test]
    fn fork_creates_two_children_and_moves_to_left() {
        let mut deck = deck();
        let left = deck.fork_active(Some("echo hi"));

        assert_eq!(left, 1);
        assert_eq!(deck.active, 1);
        assert_eq!(deck.open_count, 3);
        assert_eq!(deck.facets[0].children, vec![1, 2]);
        assert_eq!(deck.active().last_command.as_deref(), Some("echo hi"));
    }

    #[test]
    fn next_prev_are_ring_moves() {
        let mut deck = deck();
        deck.fork_active(None);

        assert_eq!(deck.switch_result(FacetMove::Next), 2);
        assert_eq!(deck.switch_result(FacetMove::Next), 0);
        assert_eq!(deck.switch_result(FacetMove::Prev), 2);
    }

    #[test]
    fn close_children_only_closes_descendants() {
        let mut deck = deck();
        deck.fork_active(None);
        deck.fork_active(None);
        deck.active = 1;
        deck.close_children();

        assert!(deck.facets[0].open);
        assert!(deck.facets[1].open);
        assert!(!deck.facets[3].open);
        assert!(!deck.facets[4].open);
    }
}
